prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName ?orgId ?modelName ?originalId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  FILTER(CONTAINS(LCASE(STR(?modelName)), LCASE("Auktionhaus_Online")))
  OPTIONAL { ?model tai:originalId ?originalId . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org bbo:name ?orgName . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
}
ORDER BY ?orgName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?label ?origId ?normId ?org ?orgName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model rdfs:label ?label . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:belongsTo ?org .
             ?org bbo:name ?orgName . }
  FILTER(
    (BOUND(?modelName) && CONTAINS(LCASE(STR(?modelName)), LCASE("Auktionhaus_Online"))) ||
    (BOUND(?label) && CONTAINS(LCASE(STR(?label)), LCASE("Auktionhaus_Online"))) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("Auktionhaus_Online"))) ||
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("Auktionhaus_Online")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?label ?orgName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model rdfs:label ?label . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org bbo:name ?orgName .
  }
  FILTER(
    (CONTAINS(LCASE(STR(?model)), LCASE("auktionhaus"))) ||
    (BOUND(?modelName) && CONTAINS(LCASE(STR(?modelName)), LCASE("auktionhaus"))) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("auktionhaus"))) ||
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("auktionhaus"))) ||
    (BOUND(?label) && CONTAINS(LCASE(STR(?label)), LCASE("auktionhaus")))
  )
}
ORDER BY ?orgName
LIMIT 25
